import subprocess
import os

def convertDocument(input_file, output_file, format_type):
    """
    Convert documents between formats using LibreOffice headless mode
    
    Args:
        input_file (str): Path to the input file
        output_file (str): Path to the output file
        format_type (str): Target format (pdf, docx, txt, etc.)
    """
    # Get the directory of the input file
    input_dir = os.path.dirname(os.path.abspath(input_file))
    
    # Build the LibreOffice command
    cmd = [
        'libreoffice',
        '--headless',
        '--convert-to',
        format_type,
        '--outdir',
        input_dir,
        input_file
    ]
    
    try:
        # Execute the command
        subprocess.run(cmd, check=True, capture_output=True)
        
        # Get the base name of the input file without extension
        input_base = os.path.splitext(os.path.basename(input_file))[0]
        
        # Construct the expected output file path
        expected_output = os.path.join(input_dir, f"{input_base}.{format_type}")
        
        # If the expected output file exists, rename it to the specified output name
        if os.path.exists(expected_output):
            os.rename(expected_output, output_file)
            
    except subprocess.CalledProcessError as e:
        raise Exception(f"Conversion failed: {e.stderr.decode()}")
    except Exception as e:
        raise Exception(f"Error during conversion: {str(e)}")